SELECT CAST(SUM(doc_count) AS REAL) / COUNT(DISTINCT user_id) AS avg_doc_accessed
FROM (
    SELECT user_id, COUNT(*) AS doc_count
    FROM document_access
    GROUP BY user_id
);

SELECT AVG(julianday('now') - julianday(users.last_login)) AS average_days_since_last_login
FROM users
JOIN documents ON users.user_id = documents.created_by;

SELECT DISTINCT user_id 
FROM document_access 
WHERE access_date = '2022-01-01';

SELECT * 
FROM documents 
WHERE doc_id = (SELECT MAX(doc_id) FROM documents);

SELECT COUNT(*)
FROM documents
WHERE created_by NOT IN (
    SELECT user_id
    FROM users
);

SELECT r.registrant_name, r.registration_number, r.contact_email, r.address, r.phone_number, r.created_by, r.created_date, r.modified_by, r.modified_date
FROM registrants AS r
ORDER BY r.registrant_name ASC;

SELECT 
    (SELECT COUNT(*) FROM documents) AS TotalDocuments,
    (SELECT COUNT(*) FROM users) AS TotalUsers;

SELECT 
    (SELECT COUNT(*) FROM documents) as total_documents, 
    (SELECT COUNT(*) FROM document_versions) as total_document_versions;
